mapper.select:
SELECT lb.*, ls.lab_name, u.nickname AS username, u.role_id FROM lab_booking lb LEFT JOIN lab_sub ls ON lb.lab_id = ls.id LEFT JOIN lab_user u ON lb.user_id = u.id WHERE lb.is_deleted = 0 AND ls.is_deleted = 0 AND u.is_deleted = 0
and lb.user_id = #{userId}
and lb.lab_id = #{labId}
and lb.booking_status = #{bookingStatus}
and lb.time_slot = #{timeSlot}
order by lb.update_time desc

SELECT COALESCE(sum(booking_num), 0)
FROM lab_booking
WHERE is_deleted = 0
  AND booking_status = 1
  AND lab_id = #{labId}
  AND booking_date = #{bookingDate}
